var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-00: <color=#ffd34c>【기록-000】 자료 갱신 절차</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-00：<color=#ffd34c>【記録-000】 資料更新手続き</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-00: <color=#ffd34c>【Record-000】 Data Update Process</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-00: <color=#ffd34c>【記錄-000】 資料更新步驟</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>코핀 컴퍼니 레거시 데이터베이스에 접속합니다.</color>","JPN":"<color=#ffd34c>コフィンカンパニーのレガシーデータベースに接続します。</color>","ENG":"<color=#ffd34c>Connecting to the Coffin Company Legacy Database.</color>","TWN":"<color=#ffd34c>正在連接科芬公司舊版資料庫。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>Query Select File – 000002 HILDE</color>","JPN":"<color=#ffd34c>Query Select File – 000002 HILDE</color>","ENG":"<color=#ffd34c>Query Select File – 000002 HILDE</color>","TWN":"<color=#ffd34c>Query Select File – 000002 HILDE</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>Subject: The Last Valkyrie</color>","JPN":"<color=#ffd34c>Subject: The Last Valkyrie</color>","ENG":"<color=#ffd34c>Subject: The Last Valkyrie</color>","TWN":"<color=#ffd34c>Subject: The Last Valkyrie</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>......열람을 종료합니다.</color>","JPN":"<color=#ffd34c>……閲覧を終了します。</color>","ENG":"<color=#ffd34c>... Closing the file.</color>","TWN":"<color=#ffd34c>……終止閱覽。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>파일을 삭제하시겠습니까?</color>","JPN":"<color=#ffd34c>ファイルを削除しますか？</color>","ENG":"<color=#ffd34c>Do you want to delete the file?</color>","TWN":"<color=#ffd34c>要刪除檔案嗎？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>Yes or No</color>","JPN":"<color=#ffd34c>Yes or No</color>","ENG":"<color=#ffd34c>Yes or No</color>","TWN":"<color=#ffd34c>Yes or No</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......지금 뭐 하시는 거죠?","JPN":"……何してるんですか？","ENG":"What are you doing?","TWN":"……你在做什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 벌써 도착했나?","JPN":"あ、もう着いたのか。","ENG":"Oh, you're already here?","TWN":"啊，妳已經到了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"약속시간보다 많이 이른데.","JPN":"約束の時間よりだいぶ早いが。","ENG":"We still have some time until we begin.","TWN":"比約定的時間還要早呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"기다리는 동안 밖에서 차나 한 잔 마시고 오는 게.......","JPN":"待っている間、外でお茶でも一杯飲んで……","ENG":"Why don't you go get a cup of tea outside while you wait—","TWN":"在等的時候妳可以喝杯茶，或是去外面晃晃……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"지금 뭐 하시는 거냐고 물었습니다.","JPN":"何をしているのか聞いたのですが。","ENG":"I asked you what you were doing.","TWN":"我問你正在幹什麼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"위험을 감수하고 기껏 스승님을 보안감찰 대상으로 올려 놓고는 이제 와서 관련 자료를 삭제하려고 하다니.......","JPN":"危険を覚悟で師匠を保安観察対象に指定したのに、関連資料を削除しようとするなんて……","ENG":"You took the risk of putting her on the inspection list, and now you're trying to delete all the relevant data?","TWN":"我冒著風險，好不容易才讓師父成為保護觀察對象，結果你卻要刪除相關資料……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"처음부터 이게 목적이었나요?","JPN":"これが目的だったんですか？","ENG":"Was this your goal from the start?","TWN":"這從一開始就是你的目的嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"알려져서는 안 될 정보를 없애려고, 일부러 자료를 모으게 한 거냐고 묻는 겁니다.","JPN":"知られてはならない情報を消すために、わざと資料を集めさせたのか？と聞いてるんです。","ENG":"Did you purposely ask me collect all the data, so you can delete it before they are exposed?","TWN":"為了刪除不能被人知道的情報，所以才要我大費周章地去收集資料。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......오해가 있군.","JPN":"……誤解してるようだな。","ENG":"You misunderstand me.","TWN":"……你誤會了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"딱히 알려져서는 안 될 정보가 있는 건 아니야.","JPN":"知られてはならない情報ではない。","ENG":"There isn't any information here that can't be opened to the public.","TWN":"不是有不能被人知道的情報。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"알려져도 될 시점이 되지 않았을 뿐이지.","JPN":"今はまだ、知られてもいい時期じゃないだけだ。","ENG":"It's just too early to release at the moment.","TWN":"只是還沒到可以被人知道的時候而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그런 말장난으로......!","JPN":"そんな屁理屈……！","ENG":"Don't try to play me like that!","TWN":"開什麼玩笑……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"이건 진심일세.","JPN":"本当だ。","ENG":"I'm being completely sincere.","TWN":"我是認真的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 증거로 딱히 자네를 <color=#ffd34c>처분</color>하려고 한 것도 아니지 않나?","JPN":"その証拠として、君を<color=#ffd34c>処分</color>しようとしたわけでもないだろ？","ENG":"As proof, I haven't tried to <color=#ffd34c>dispose</color> of you.","TWN":"沒有把你<color=#ffd34c>處理</color>掉，不就是最好的證據嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네 정도의 분별력이 있다면 이 정보가 <color=#ffd34c>아직은</color> 알려지지 않아야 한다는 것쯤은 납득할 수 있겠지.","JPN":"君であれば、この情報が<color=#ffd34c>まだ</color>知られてはならないという、私の考えに納得するはずだ。","ENG":"If you are as sensible as I think you are, you should understand that this information cannot be revealed <color=#ffd34c>yet</color>.","TWN":"像你這麼明智的人，應該可以理解為什麼這個情報<color=#ffd34c>還</color>不能被人知道吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......그러면 <color=#ffd34c>제가 아닌</color> 그 정보의 <color=#ffd34c>다른 출처</color>는요?","JPN":"……それじゃあ<color=#ffd34c>私以外の、</color>情報の<color=#ffd34c>出処</color>は？","ENG":"Then what about the <color=#ffd34c>other source</color> of information <color=#ffd34c>besides me</color>?","TWN":"……那麼，<color=#ffd34c>除了我</color>以外，其他的<color=#ffd34c>情報來源</color>呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그건 지금부터 자세한 보고를 들어 봐야겠지.","JPN":"それは今から、詳細な報告を受けた後で判断する。","ENG":"That depends on today's report.","TWN":"那就得聽你接下來的詳細報告了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"좀 이르긴 하지만 커피 마실 기분이 아닌 것 같으니 시작하도록 하지.","JPN":"少し早いが、コーヒーを飲む気分でもないそうだし、さっそく始めよう。","ENG":"It's a bit early, but I don't think you're in the mood for coffee. Let's begin.","TWN":"雖然有點早，但我看你好像沒什麼心情喝咖啡，那就直接開始吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......알겠습니다.","JPN":"……わかりました。","ENG":"Fine.","TWN":"……知道了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"보고 대상의 자세한 행동 분석을 위해 이번에는 과거 자료를 뒤져 봤습니다.","JPN":"報告対象の詳細な行動を分析するために、今回は過去の資料を探しました。","ENG":"In order to analyze the subject's behaviors, I searched through her past records.","TWN":"為了分析報告該對象的詳細行動，這次我查閱了大量的過去資料。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"생각해 보면 <color=#ff3636>[DATA EXPUNGED]</color> 시절에도 스승님의 과거 자료는 딱히 공개된 게 없었죠.","JPN":"考えてみれば<color=#ff3636>[DATA EXPUNGED]</color>時代にも、師匠の過去に関する資料は、特に公開されていませんでした。","ENG":"Come to think of it, Master's past records were not disclosed even during her days in the <color=#ff3636>[DATA EXPUNGED]</color>.","TWN":"仔細想想，就是<color=#ff3636>[DATA_EXPUNGED]</color>時代，師父過去的資料也沒有被特別公開過。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>[DATA EXPUNGED]</color> 설립 초기, 아무런 실전 데이터나 노하우도 없는 상황에서 갑작스럽게 등장한 최강의 카운터라니.......","JPN":"<color=#ff3636>[DATA EXPUNGED]</color>設立初期、何の実戦データもノウハウもない状況で、突然現れた最強のカウンター……","ENG":"She was the ultimate Counter who appeared during the early days of <color=#ff3636>[DATA EXPUNGED]</color>, when there was no practical data or experience in the industry.","TWN":"<color=#ff3636>[DATA EXPUNGED]</color>設立初期，在沒有任何實戰數據和經驗的情況下，突然登場的最強的制裁者……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"지금 생각해 보면 정말 수상하기 짝이 없는 일이었죠.","JPN":"今になって考えてみれば、本当に怪しいですね。","ENG":"Looking back now, it was all very suspicious.","TWN":"現在想想，這真是件非常奇怪的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 점에 대해서는 나도 나름대로 정보 통제를 잘했다고 생각하는데 말이야.......","JPN":"その点に関しては、私もそれなりに上手く情報をコントロールしてきたと思ったが……","ENG":"I thought I did well in placing that information under control.","TWN":"關於這一點，我以為我情報操控做得很好……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>발키리</color>라는 키워드로 여기까지 추적해 내다니...... 정말 기발하군.","JPN":"<color=#ffd34c>ヴァルキリー</color>というキーワードだけで、ここまで追跡するとは……実に素晴らしい。","ENG":"But you managed to track down so much information with only the keyword <color=#ffd34c>Valkyrie</color>. Brilliant.","TWN":"但妳竟然能靠著<color=#ffd34c>女武神</color>這個關鍵字查到這裡……真是了不起。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"처음에는 저도 단순히 스승님의 별명들 중 하나라고만 생각했죠.","JPN":"私も初めは、単なる師匠の異名だと思っていました。","ENG":"At first, I thought it was just one of Master's nicknames.","TWN":"一開始我也以為這單純是師父的其中一個暱稱。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만 <color=#ffd34c>발키리</color>는 그렇다 쳐도 <color=#ffd34c>최후의 발키리</color>라는 건 이상하지 않나요?","JPN":"しかし、<color=#ffd34c>ヴァルキリー</color>だけならわかりますが、<color=#ffd34c>ラストヴァルキリー</color>というのはおかしくありませんか？","ENG":"Just <color=#ffd34c>Valkyrie</color> is fine. But isn't it weird to call her the <color=#ffd34c>Last Valkyrie</color>?","TWN":"但<color=#ffd34c>女武神</color>就算了，說<color=#ffd34c>最後的女武神</color>難道不奇怪嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"과연...... 그럴 만해.","JPN":"確かに……そうだな。","ENG":"I see... That's reasonable.","TWN":"原來如此……這倒是。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래서 어디까지 알아냈지?","JPN":"それで、どこまでわかったんだ？","ENG":"So how deep did you dig?","TWN":"所以妳查到什麼程度了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>최후의 발키리</color>라는 게 스승님의 별명이 아니라 <color=#ff3636>[DATA EXPUNGED]</color>라는 것까지는 알아냈습니다.","JPN":"<color=#ffd34c>ラストヴァルキリー</color>というのが、師匠の異名ではなく<color=#ff3636>[DATA EXPUNGED]</color>であるというところまではわかりました。","ENG":"I found out that <color=#ffd34c>Last Valkyrie</color> isn't Master's nickname, but it's actually referring to <color=#ff3636>[DATA EXPUNGED]</color>.","TWN":"我查到<color=#ffd34c>最後的女武神</color>不是師父的暱稱，而是在說<color=#ff3636>[DATA_EXPUNGED]</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"대체 어떻게 그게 가능한지는 모르겠지만요.","JPN":"どんな方法を使ったのかまではわかりませんが。","ENG":"Although I'm not sure how that's possible.","TWN":"真不知道到底為什麼會這樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"중요한 건 <color=#ffd34c>어떻게</color>가 아니라 <color=#ffd34c>언제</color>의 <color=#ff3636>[DATA EXPUNGED]</color>인가 하는 거지.","JPN":"重要なのは<color=#ffd34c>どんな方法を使ったのか</color>ではなく、<color=#ffd34c>いつ</color>の<color=#ff3636>[DATA EXPUNGED]</color>なのかというところだ。","ENG":"What's important is not <color=#ffd34c>how</color>, but <color=#ffd34c>when</color> did <color=#ff3636>[DATA EXPUNGED]</color> exist.","TWN":"重要的不是<color=#ffd34c>怎麼</color>，而是<color=#ffd34c>何時</color>的<color=#ff3636>[DATA_EXPUNGED]</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네도 그 정도는 추측하고 있을 텐데?","JPN":"君もそれくらいは推測してるだろ？","ENG":"I'm sure you've already guessed that.","TWN":"你應該也猜得到吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......<color=#ff3636>[DATA EXPUNGED]</color> 녀석의 의심이 맞았나 보군요.","JPN":"……<color=#ff3636>[DATA EXPUNGED]</color>の予想が当たったようですね。","ENG":"<color=#ff3636>[DATA EXPUNGED]</color>'s suspicions must be correct.","TWN":"……看來<color=#ff3636>[DATA_EXPUNGED]</color>那傢伙的懷疑是對的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이번에도 그 녀석이 보내 준 자료를 참고로 가설을 세웠으니까요.","JPN":"今回も、彼が送ってくれた資料を基に仮説を立てたので。","ENG":"I developed this hypothesis based on the data he sent me.","TWN":"這次也是以那傢伙給我的資料作為參考，才立下了假設。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 그 친구......","JPN":"ああ……","ENG":"Ah, him.","TWN":"啊，那位朋友……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그러고 보니 펜릴 전대에 있던 시절에도 머리가 잘 돌아가긴 했지.","JPN":"そういえばフェンリル戦隊にいた頃も、頭が切れるやつだったな。","ENG":"He was pretty smart when he was in the Fenrir Division.","TWN":"說起來，在芬里爾戰隊的時候，他的頭腦就非常好了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"행방불명이다가 갑자기 나타나서 보고 대상과 한바탕 푸닥거리를 한 모양인데 그 사이에 잘도 그런 조사를 했군.","JPN":"行方不明だったのに突然現れて、報告対象とひと悶着あったようだが、その隙によくここまで調べたな。","ENG":"He had been missing for a while, and he suddenly appeared out of nowhere to mess with our subject. I wonder when he had the time to do the research.","TWN":"行蹤不明的他突然出現，還不斷地和我們的對象起衝突，真虧他能調查得這麼深入。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"제가 알고 있는 건 여기까지입니다.","JPN":"私が知っているのはここまでです。","ENG":"That's all I know for now.","TWN":"我知道的事情就到這裡為止了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이제 <color=#ffd34c>다른 출처</color>도 모두 알게 되셨는데 어떡하실 생각이시죠?","JPN":"これで<color=#ffd34c>他の出処</color>もすべて報告しましたが、どうされますか？","ENG":"Now that you know about the <color=#ffd34c>other source</color>, what are you going to do?","TWN":"現在，<color=#ffd34c>其他的來源</color>也都知道了，您打算怎麼做？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......뭘 어떡하나?","JPN":"……どうするも何も。","ENG":"What can I do?","TWN":"……什麼怎麼做？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 친구가 뭘 하든 내가 어쩔 수 있는 것도 아니고 그저 기다려 볼 수밖에.","JPN":"彼が何をしようと私に止める権利はないし、ただ待つしかないな。","ENG":"Whatever he does, I don't have any means to stop him. All I can do is to wait.","TWN":"不管那位朋友在做什麼，我都拿他沒辦法，只能等待了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......생각보다 맥빠지는 반응이시군요.","JPN":"……呆気ないですね。","ENG":"That's not the response I expected.","TWN":"……您的反應比想像中的還要糟糕呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"세상 일이 대부분 그렇다네. 별로 특별할 게 없지.","JPN":"世の中の大抵のことは、そんなものだ。特別なことなんてない。","ENG":"That's what happens most of the time. Nothing special.","TWN":"世上的事情大部分都是這樣。沒什麼特別的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......그럼 오늘의 보고는 마치도록 하겠습니다.","JPN":"……では、本日の報告を終了いたします。","ENG":"Well, that's the end of today's report.","TWN":"……那麼今天的報告就到這裡吧"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"잠깐만 기다리게.","JPN":"待ってくれ。","ENG":"Hold on for a second.","TWN":"稍等一下。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"뭔가요?","JPN":"何ですか？","ENG":"What is it?","TWN":"什麼事？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래도 애써 여기까지 알아냈는데 자네에게도 작은 선물 정도는 줘야겠지.","JPN":"ここまで調べた君にプレゼントをやろう。","ENG":"You managed to gather so much information. You deserve a small gift.","TWN":"既然你都查到這裡了，至少也要給你一個小小的禮物吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"선물요?","JPN":"プレゼント？","ENG":"A gift?","TWN":"禮物？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"힐데 소대장 말일세...... 자네도 그 이름이 본명이 아니라는 건 알고 있겠지?","JPN":"君も……、ヒルデ小隊長の名前が本名じゃないことには気づいてるだろ？","ENG":"Hilde... You already know that it's not her real name, don't you?","TWN":"希爾德小隊長……你也知道這個名字不是本名吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"설마......?","JPN":"まさか……？","ENG":"You mean...","TWN":"難道……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그녀의 본명은 <color=#ff3636>[DATA EXPUNGED]</color>라네.","JPN":"彼女の本名は<color=#ff3636>[DATA EXPUNGED]</color>だ。","ENG":"Her real name is <color=#ff3636>[DATA EXPUNGED]</color>.","TWN":"她的本名是<color=#ff3636>[DATA_EXPUNGED]</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"지금...... 농담하시는 겁니까......?!","JPN":"冗談……、ですよね……？","ENG":"Are you... joking now?!","TWN":"你……現在是在跟我開玩笑嗎……？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하하, 꽤 놀란 모양이군.","JPN":"はは、驚いたようだな。","ENG":"Hah hah, you must be surprised.","TWN":"哈哈，你很驚訝呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그러니 앞으로도 날 흥미롭게 할 정보를 많이 찾아오기 바라네.","JPN":"これからも私を楽しませてくれる情報を探し出してくれ。","ENG":"Make sure to keep on bringing more interesting information.","TWN":"所以，希望之後你能找到更多讓我感興趣的情報。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"혹시 내가 또다른 선물을 줄지도 모르니까 말이야.","JPN":"もしかしたら、またプレゼントをもらえるかもしれないだろ？","ENG":"There might be some more gifts I can give you.","TWN":"搞不好我會給你別的禮物也說不定。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그럼 다음 보고 때 보도록 하지.","JPN":"では、次の報告の時に会おう。","ENG":"I'll be looking forward to your next report.","TWN":"那下次報告的時候再見吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};